#else
#define ORDER 256
#endif

typedef struct record {
    int value;
} record;

typedef struct knode {
    int location;
    int indices[ORDER + 1];
    int keys[ORDER + 1];
    int is_leaf;
    int num_keys;
} knode;

kernel void findK(
    long height,
    knode *knodesD,
    long knodes_elem,
    record *recordsD,
    long *currKnodeD,
    long *offsetD,
    int *keysD,
    record *ansD)
{
    int thid = get_local_id(0);
    int bid = get_group_id(0);

    int i;
    for(i = 0; i < height; i++){
        if((knodesD[currKnodeD[bid]].keys[thid]) <= keysD[bid] && 
           (knodesD[currKnodeD[bid]].keys[thid+1] > keysD[bid])){
            if(knodesD[offsetD[bid]].indices[thid] < knodes_elem){
                offsetD[bid] = knodesD[offsetD[bid]].indices[thid];
            }
        }
        barrier(CLK_LOCAL_MEM_FENCE);

        if(thid==0){
            currKnodeD[bid] = offsetD[bid];
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    if(knodesD[currKnodeD[bid]].keys[thid] == keysD[bid]){
        ansD[bid].value = recordsD[knodesD[currKnodeD[bid]].indices[thid]].value;
    }
}

