kernel void
bpnn_layerforward_ocl(float *input_ocl,
                      float *output_hidden_ocl,
                      float *input_hidden_ocl,
                      float *hidden_partial_sum,
                      int in,
                      int hid) 
{
   int by = get_block_id(1);
   int tx = get_local_id(0);
   int ty = get_local_id(1);

   int index =  ( hid + 1 ) * HEIGHT * by + ( hid + 1 ) * ty + tx + 1 + ( hid + 1 );  

   int index_in = HEIGHT * by + ty + 1;

   local float input_node[HEIGHT];
   local float weight_matrix[HEIGHT][WIDTH];


   if ( tx == 0 )
   input_node[ty] = input_ocl[index_in];

   barrier(CLK_LOCAL_MEM_FENCE);

   weight_matrix[ty][tx] = input_hidden_ocl[index];

   barrier(CLK_LOCAL_MEM_FENCE);

   weight_matrix[ty][tx] = weight_matrix[ty][tx] * input_node[ty];

   barrier(CLK_LOCAL_MEM_FENCE);   

   for ( int i = 1 ; i <= log2((float)HEIGHT) ; i++){

       int power_two = pow(2.0f, (float)i);

       if( ty % power_two == 0 )
       weight_matrix[ty][tx] = weight_matrix[ty][tx] + weight_matrix[ty + power_two/2][tx];

       barrier(CLK_LOCAL_MEM_FENCE);

   }



   input_hidden_ocl[index] = weight_matrix[ty][tx];

   barrier(CLK_LOCAL_MEM_FENCE);

   if ( tx == 0 ) {
       hidden_partial_sum[by * hid + ty] = weight_matrix[tx][ty];
   }

}


