    float y;
    float z;
} float3;

static inline void compute_flux_contribution(float density, float3 momentum, float density_energy, float pressure, float3 velocity, 
                                              float3* fc_momentum_x, float3* fc_momentum_y, float3* fc_momentum_z, float3* fc_density_energy)
{
