void kernel(
    __global params_common_change* d_common_change_ptr,
    __global params_common* d_common_ptr,
    __global params_unique* d_unique_ptr
) {
    __local fp in_partial_sum[51];
    __local fp in_sqr_partial_sum[51];
    __local fp in_final_sum;
    __local fp in_sqr_final_sum;
    __local fp denomT;
    __local fp par_max_val[131];
    __local int par_max_coo[131];
    __local fp d_in_mod_temp[2601];

    fp* d_in;
    int rot_row;
    int rot_col;
    int in2_rowlow;
    int in2_collow;
    int ic;
    int jc;
    int jp1;
    int ja1, ja2;
    int ip1;
    int ia1, ia2;
    int ja, jb;
    int ia, ib;
    fp s;
    int i;
    int j;
    int row;
    int col;
    int ori_row;
    int ori_col;
    int position;
    fp sum;
    int pos_ori;
    fp temp;
    fp temp2;
    int location;
    int cent;
    int tMask_row;
    int tMask_col;
    fp largest_value_current = 0;
    fp largest_value = 0;
    int largest_coordinate_current = 0;
    int largest_coordinate = 0;
    fp fin_max_val = 0;
    int fin_max_coo = 0;
    int largest_row;
    int largest_col;
    int offset_row;
    int offset_col;
    fp mean;
    fp mean_sqr;
    fp variance;
    fp deviation;
    int pointer;
    int ori_pointer;
    int loc_pointer;

    int bx = get_group_id(0);
    int tx = get_local_id(0);
    int ei_new;

    params_common_change d_common_change = d_common_change_ptr[0];
    params_common d_common = d_common_ptr[0];
    params_unique d_unique = d_unique_ptr[bx];

    if(d_common_change.frame_no == 0) {
        d_in = &d_unique.d_T[d_unique.in_pointer];

        ei_new = tx;
        if(ei_new == 0) {
            pointer = d_unique.point_no * d_common.no_frames + d_common_change.frame_no;
            d_unique.d_tRowLoc[pointer] = d_unique.d_Row[d_unique.point_no];
            d_unique.d_tColLoc[pointer] = d_unique.d_Col[d_unique.point_no];
        }

        ei_new = tx;
        while(ei_new < d_common.in_elem) {
            row = (ei_new + 1) % d_common.in_rows - 1;
            col = (ei_new + 1) / d_common.in_rows + 1 - 1;
            if((ei_new + 1) % d_common.in_rows == 0) {
                row = d_common.in_rows - 1;
                col = col - 1;
            }

            ori_row = d_unique.d_Row[d_unique.point_no] - 25 + row - 1;
            ori_col = d_unique.d_Col[d_unique.point_no] - 25 + col - 1;
            ori_pointer = ori_col * d_common.frame_rows + ori_row;

            d_in[col * d_common.in_rows + row] = d_common_change.d_frame[ori_pointer];

            ei_new = ei_new + NUMBER_THREADS;
        }
    }

    if(d_common_change.frame_no != 0) {
        in2_rowlow = d_unique.d_Row[d_unique.point_no] - d_common.sSize;
        in2_collow = d_unique.d_Col[d_unique.point_no] - d_common.sSize;

        ei_new = tx;
        while(ei_new < d_common.in2_elem) {
            row = (ei_new + 1) % d_common.in2_rows - 1;
            col = (ei_new + 1) / d_common.in2_rows + 1 - 1;
            if((ei_new + 1) % d_common.in2_rows == 0) {
                row = d_common.in2_rows - 1;
                col = col - 1;
            }

            ori_row = row + in2_rowlow - 1;
            ori_col = col + in2_collow - 1;
            d_unique.d_in2[ei_new] = d_common_change.d_frame[ori_col * d_common.frame_rows + ori_row];

            ei_new = ei_new + NUMBER_THREADS;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        d_in = &d_unique.d_T[d_unique.in_pointer];

        ei_new = tx;
        while(ei_new < d_common.in_elem) {
            row = (ei_new + 1) % d_common.in_rows - 1;
            col = (ei_new + 1) / d_common.in_rows + 1 - 1;
            if((ei_new + 1) % d_common.in_rows == 0) {
                row = d_common.in_rows - 1;
                col = col - 1;
            }

            rot_row = (d_common.in_rows - 1) - row;
            rot_col = (d_common.in_rows - 1) - col;
            d_in_mod_temp[ei_new] = d_in[rot_col * d_common.in_rows + rot_row];

            ei_new = ei_new + NUMBER_THREADS;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        ei_new = tx;
        while(ei_new < d_common.conv_elem) {
            ic = (ei_new + 1) % d_common.conv_rows;
            jc = (ei_new + 1) / d_common.conv_rows + 1;
            if((ei_new + 1) % d_common.conv_rows == 0) {
                ic = d_common.conv_rows;
                jc = jc - 1;
            }

            j = jc + d_common.joffset;
            jp1 = j + 1;
            if(d_common.in2_cols < jp1) {
                ja1 = jp1 - d_common.in2_cols;
            } else {
                ja1 = 1;
            }
            if(d_common.in_cols < j) {
                ja2 = d_common.in_cols;
            } else {
                ja2 = j;
            }

            i = ic + d_common.ioffset;
            ip1 = i + 1;

            if(d_common.in2_rows < ip1) {
                ia1 = ip1 - d_common.in2_rows;
            } else {
                ia1 = 1;
            }
            if(d_common.in_rows < i) {
                ia2 = d_common.in_rows;
            } else {
                ia2 = i;
            }

            s = 0;

            for(ja = ja1; ja <= ja2; ja++) {
                jb = jp1 - ja;
                for(ia = ia1; ia <= ia2; ia++) {
                    ib = ip1 - ia;
                    s = s + d_in_mod_temp[d_common.in_rows * (ja - 1) + ia - 1] * d_unique.d_in2[d_common.in2_rows * (jb - 1) + ib - 1];
                }
            }

            d_unique.d_conv[ei_new] = s;

            ei_new = ei_new + NUMBER_THREADS;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        ei_new = tx;
        while(ei_new < d_common.in2_pad_cumv_elem) {
            row = (ei_new + 1) % d_common.in2_pad_cumv_rows - 1;
            col = (ei_new + 1) / d_common.in2_pad_cumv_rows + 1 - 1;
            if((ei_new + 1) % d_common.in2_pad_cumv_rows == 0) {
                row = d_common.in2_pad_cumv_rows - 1;
                col = col - 1;
            }

            if(row > (d_common.in2_pad_add_rows - 1) &&
               row < (d_common.in2_pad_add_rows + d_common.in2_rows) &&
               col > (d_common.in2_pad_add_cols - 1) &&
               col < (d_common.in2_pad_add_cols + d_common.in2_cols)) {
                ori_row = row - d_common.in2_pad_add_rows;
                ori_col = col - d_common.in2_pad_add_cols;
                d_unique.d_in2_pad_cumv[ei_new] = d_unique.d_in2[ori_col * d_common.in2_rows + ori_row];
            } else {
                d_unique.d_in2_pad_cumv[ei_new] = 0;
            }

            ei_new = ei_new + NUMBER_THREADS;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        ei_new = tx;
        while(ei_new < d_common.in2_pad_cumv_cols) {
            pos_ori = ei_new * d_common.in2_pad_cumv_rows;

            sum = 0;
            for(position = pos_ori; position < pos_ori + d_common.in2_pad_cumv_rows; position = position + 1) {
                d_unique.d_in2_pad_cumv[position] = d_unique.d_in2_pad_cumv[position] + sum;
                sum = d_unique.d_in2_pad_cumv[position];
            }

            ei_new = ei_new + NUMBER_THREADS;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        ei_new = tx;
        while(ei_new < d_common.in2_pad_cumv_sel_elem) {
            row = (ei_new + 1) % d_common.in2_pad_cumv_sel_rows - 1;
            col = (ei_new + 1) / d_common.in2_pad_cumv_sel_rows + 1 - 1;
            if((ei_new + 1) % d_common.in2_pad_cumv_sel_rows == 0) {
                row = d_common.in2_pad_cumv_sel_rows - 1;
                col = col - 1;
            }

            ori_row = row + d_common.in2_pad_cumv_sel_rowlow - 1;
            ori_col = col + d_common.in2_pad_cumv_sel_collow - 1;
