            ei_new = ei_new + NUMBER_THREADS;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        cent = d_common.sSize + d_common.tSize + 1;
        if(d_common_change.frame_no == 0) {
            tMask_row = cent + d_unique.d_Row[d_unique.point_no] - d_unique.d_Row[d_unique.point_no] - 1;
            tMask_col = cent + d_unique.d_Col[d_unique.point_no] - d_unique.d_Col[d_unique.point_no] - 1;
        } else {
            pointer = d_common_change.frame_no - 1 + d_unique.point_no * d_common.no_frames;
            tMask_row = cent + d_unique.d_tRowLoc[pointer] - d_unique.d_Row[d_unique.point_no] - 1;
            tMask_col = cent + d_unique.d_tColLoc[pointer] - d_unique.d_Col[d_unique.point_no] - 1;
        }

        ei_new = tx;
        while(ei_new < d_common.tMask_elem) {
            location = tMask_col * d_common.tMask_rows + tMask_row;

