    if(d_common_change.frame_no != 0 && (d_common_change.frame_no) % 10 == 0) {
        loc_pointer = d_unique.point_no * d_common.no_frames + d_common_change.frame_no;
        d_unique.d_Row[d_unique.point_no] = d_unique.d_tRowLoc[loc_pointer];
        d_unique.d_Col[d_unique.point_no] = d_unique.d_tColLoc[loc_pointer];

        ei_new = tx;
        while(ei_new < d_common.in_elem) {
            row = (ei_new + 1) % d_common.in_rows - 1;
            col = (ei_new + 1) / d_common.in_rows + 1 - 1;
            if((ei_new + 1) % d_common.in_rows == 0) {
                row = d_common.in_rows - 1;
                col = col - 1;
            }

            ori_row = d_unique.d_Row[d_unique.point_no] - 25 + row - 1;
            ori_col = d_unique.d_Col[d_unique.point_no] - 25 + col - 1;
            ori_pointer = ori_col * d_common.frame_rows + ori_row;

            d_in[ei_new] = d_common.alpha * d_in[ei_new] + (1.00 - d_common.alpha) * d_common_change.d_frame[ori_pointer];

            ei_new = ei_new + NUMBER_THREADS;
        }
    }
