                 params,
                 params_offset_Dyad,
                 com,
                 com_offset_Dyad,
                 CaDyad);

    CaSL = initvalu[36]*1e3;

    kernel_cam_2(timeinst,
                 initvalu,
                 finavalu,
                 valu_offset_SL,
                 params,
                 params_offset_SL,
                 com,
                 com_offset_SL,
                 CaSL);

