    I_CaNa_junc = (Fjunc_CaL*ibarna_j*d_initvalu_4*d_initvalu_5*(1-d_initvalu_6)*pow(Q10CaL,Qpow))*0.45;
    I_CaNa_sl = (Fsl_CaL*ibarna_sl*d_initvalu_4*d_initvalu_5*(1-d_initvalu_7)*pow(Q10CaL,Qpow))*0.45;

    Ka_junc = 1/(1+pow((Kdact/d_initvalu_36),3));
    Ka_sl = 1/(1+pow((Kdact/d_initvalu_37),3));
    s1_junc = exp(nu*d_initvalu_39*FoRT)*pow(d_initvalu_32,3)*Cao;
    s1_sl = exp(nu*d_initvalu_39*FoRT)*pow(d_initvalu_33,3)*Cao;
    s2_junc = exp((nu-1)*d_initvalu_39*FoRT)*pow(Nao,3)*d_initvalu_36;
    s3_junc = (KmCai*pow(Nao,3)*(1+pow((d_initvalu_32/KmNai),3))+pow(KmNao,3)*d_initvalu_36+ pow(KmNai,3)*Cao*(1+d_initvalu_36/KmCai)+KmCao*pow(d_initvalu_32,3)+pow(d_initvalu_32,3)*Cao+pow(Nao,3)*d_initvalu_36)*(1+ksat*exp((nu-1)*d_initvalu_39*FoRT));
    s2_sl = exp((nu-1)*d_initvalu_39*FoRT)*pow(Nao,3)*d_initvalu_37;
    s3_sl = (KmCai*pow(Nao,3)*(1+pow((d_initvalu_33/KmNai),3)) + pow(KmNao,3)*d_initvalu_37+pow(KmNai,3)*Cao*(1+d_initvalu_37/KmCai)+KmCao*pow(d_initvalu_33,3)+pow(d_initvalu_33,3)*Cao+pow(Nao,3)*d_initvalu_37)*(1+ksat*exp((nu-1)*d_initvalu_39*FoRT));
    I_ncx_junc = Fjunc*IbarNCX*pow(Q10NCX,Qpow)*Ka_junc*(s1_junc-s2_junc)/s3_junc;
    I_ncx_sl = Fsl*IbarNCX*pow(Q10NCX,Qpow)*Ka_sl*(s1_sl-s2_sl)/s3_sl;
    I_ncx = I_ncx_junc+I_ncx_sl;
    d_finavalu[offset_45]=2*I_ncx*Cmem/(Vmyo*2*Frdy)*1e3;

    I_pca_junc = Fjunc*pow(Q10SLCaP,Qpow)*IbarSLCaP*pow(d_initvalu_36,1.6)/(pow(KmPCa,1.6)+pow(d_initvalu_36,1.6));
    I_pca_sl = Fsl*pow(Q10SLCaP,Qpow)*IbarSLCaP*pow(d_initvalu_37,1.6)/(pow(KmPCa,1.6)+pow(d_initvalu_37,1.6));
    I_pca = I_pca_junc+I_pca_sl;
    d_finavalu[offset_44]=-I_pca*Cmem/(Vmyo*2*Frdy)*1e3;

    I_cabk_junc = Fjunc*GCaB*(d_initvalu_39-eca_junc);
    I_cabk_sl = Fsl*GCaB*(d_initvalu_39-eca_sl);
    I_cabk = I_cabk_junc+I_cabk_sl;
    d_finavalu[offset_46]=-I_cabk*Cmem/(Vmyo*2*Frdy)*1e3;

    MaxSR = 15;
    MinSR = 1;
    kCaSR = MaxSR - (MaxSR-MinSR)/(1+pow(ec50SR/d_initvalu_31,2.5));
    koSRCa = koCa/kCaSR;
    kiSRCa = kiCa*kCaSR;
    RI = 1-d_initvalu_14-d_initvalu_15-d_initvalu_16;
    d_finavalu[offset_14] = (kim*RI-kiSRCa*d_initvalu_36*d_initvalu_14)-(koSRCa*pow(d_initvalu_36,2)*d_initvalu_14-kom*d_initvalu_15);
    d_finavalu[offset_15] = (koSRCa*pow(d_initvalu_36,2)*d_initvalu_14-kom*d_initvalu_15)-(kiSRCa*d_initvalu_36*d_initvalu_15-kim*d_initvalu_16);
    d_finavalu[offset_16] = (kiSRCa*d_initvalu_36*d_initvalu_15-kim*d_initvalu_16)-(kom*d_initvalu_16-koSRCa*pow(d_initvalu_36,2)*RI);
    J_SRCarel = ks*d_initvalu_15*(d_initvalu_31-d_initvalu_36);
    J_serca = pow(Q10SRCaP,Qpow)*Vmax_SRCaP*(pow((d_initvalu_38/Kmf),hillSRCaP)-pow((d_initvalu_31/Kmr),hillSRCaP))
                                            /(1+pow((d_initvalu_38/Kmf),hillSRCaP)+pow((d_initvalu_31/Kmr),hillSRCaP));
    J_SRleak = 5.348e-6*(d_initvalu_31-d_initvalu_36);

    d_finavalu[offset_17] = kon_na*d_initvalu_32*(Bmax_Naj-d_initvalu_17)-koff_na*d_initvalu_17;
    d_finavalu[offset_18] = kon_na*d_initvalu_33*(Bmax_Nasl-d_initvalu_18)-koff_na*d_initvalu_18;

    d_finavalu[offset_19] = kon_tncl*d_initvalu_38*(Bmax_TnClow-d_initvalu_19)-koff_tncl*d_initvalu_19;
    d_finavalu[offset_20] = kon_tnchca*d_initvalu_38*(Bmax_TnChigh-d_initvalu_20-d_initvalu_21)-koff_tnchca*d_initvalu_20;
    d_finavalu[offset_21] = kon_tnchmg*Mgi*(Bmax_TnChigh-d_initvalu_20-d_initvalu_21)-koff_tnchmg*d_initvalu_21;
    d_finavalu[offset_22] = 0;
    d_finavalu[offset_23] = kon_myoca*d_initvalu_38*(Bmax_myosin-d_initvalu_23-d_initvalu_24)-koff_myoca*d_initvalu_23;
    d_finavalu[offset_24] = kon_myomg*Mgi*(Bmax_myosin-d_initvalu_23-d_initvalu_24)-koff_myomg*d_initvalu_24;
    d_finavalu[offset_25] = kon_sr*d_initvalu_38*(Bmax_SR-d_initvalu_25)-koff_sr*d_initvalu_25;
    J_CaB_cytosol = d_finavalu[offset_19] + d_finavalu[offset_20] + d_finavalu[offset_21] + d_finavalu[offset_22] + d_finavalu[offset_23] + d_finavalu[offset_24] + d_finavalu[offset_25];

    d_finavalu[offset_26] = kon_sll*d_initvalu_36*(Bmax_SLlowj-d_initvalu_26)-koff_sll*d_initvalu_26;
    d_finavalu[offset_27] = kon_sll*d_initvalu_37*(Bmax_SLlowsl-d_initvalu_27)-koff_sll*d_initvalu_27;
    d_finavalu[offset_28] = kon_slh*d_initvalu_36*(Bmax_SLhighj-d_initvalu_28)-koff_slh*d_initvalu_28;
    d_finavalu[offset_29] = kon_slh*d_initvalu_37*(Bmax_SLhighsl-d_initvalu_29)-koff_slh*d_initvalu_29;
    J_CaB_junction = d_finavalu[offset_26]+d_finavalu[offset_28];
    J_CaB_sl = d_finavalu[offset_27]+d_finavalu[offset_29];

    d_finavalu[offset_30] = kon_csqn*d_initvalu_31*(Bmax_Csqn-d_initvalu_30)-koff_csqn*d_initvalu_30;
    oneovervsr = 1/Vsr;
    d_finavalu[offset_31] = J_serca*Vmyo*oneovervsr-(J_SRleak*Vmyo*oneovervsr+J_SRCarel)-d_finavalu[offset_30];

    I_Na_tot_junc = I_Na_junc+I_nabk_junc+3*I_ncx_junc+3*I_nak_junc+I_CaNa_junc;
    I_Na_tot_sl = I_Na_sl+I_nabk_sl+3*I_ncx_sl+3*I_nak_sl+I_CaNa_sl;
    d_finavalu[offset_32] = -I_Na_tot_junc*Cmem/(Vjunc*Frdy)+J_na_juncsl/Vjunc*(d_initvalu_33-d_initvalu_32)-d_finavalu[offset_17];
    oneovervsl = 1/Vsl;
    d_finavalu[offset_33] = -I_Na_tot_sl*Cmem*oneovervsl/Frdy+J_na_juncsl*oneovervsl*(d_initvalu_32-d_initvalu_33)+J_na_slmyo*oneovervsl*(d_initvalu_34-d_initvalu_33)-d_finavalu[offset_18];
    d_finavalu[offset_34] = J_na_slmyo/Vmyo*(d_initvalu_33-d_initvalu_34);

    I_K_tot = I_to+I_kr+I_ks+I_ki-2*I_nak+I_CaK+I_kp;
    d_finavalu[offset_35] = 0;

    I_Ca_tot_junc = I_Ca_junc+I_cabk_junc+I_pca_junc-2*I_ncx_junc;
    I_Ca_tot_sl = I_Ca_sl+I_cabk_sl+I_pca_sl-2*I_ncx_sl;
    d_finavalu[offset_36] = -I_Ca_tot_junc*Cmem/(Vjunc*2*Frdy)+J_ca_juncsl/Vjunc*(d_initvalu_37-d_initvalu_36)
             - J_CaB_junction+(J_SRCarel)*Vsr/Vjunc+J_SRleak*Vmyo/Vjunc;
    d_finavalu[offset_37] = -I_Ca_tot_sl*Cmem/(Vsl*2*Frdy)+J_ca_juncsl/Vsl*(d_initvalu_36-d_initvalu_37)
             + J_ca_slmyo/Vsl*(d_initvalu_38-d_initvalu_37)-J_CaB_sl;
    d_finavalu[offset_38] = -J_serca-J_CaB_cytosol +J_ca_slmyo/Vmyo*(d_initvalu_37-d_initvalu_38);

    state = 1;
    if(state == 0){
        I_app = 0;
    }
    else if(state == 1){
        if(fmod(timeinst,cycleLength) <= 5){
            I_app = 9.5;
        }
        else{
            I_app = 0.0;
        }
    }
    else if(state == 2){
        V_hold = -55;
        V_test = 0;
        if(timeinst>0.5 && timeinst<200.5){
            V_clamp = V_test;
        }
        else{
            V_clamp = V_hold;
        }
        R_clamp = 0.04;
        I_app = (V_clamp-d_initvalu_39)/R_clamp;
    }

    I_Na_tot = I_Na_tot_junc + I_Na_tot_sl;
    I_Cl_tot = I_ClCa+I_Clbk;
    I_Ca_tot = I_Ca_tot_junc+I_Ca_tot_sl;
    I_tot = I_Na_tot+I_Cl_tot+I_Ca_tot+I_K_tot;
    d_finavalu[offset_39] = -(I_tot-I_app);

    d_finavalu[offset_41] = 0;
    d_finavalu[offset_42] = 0;

}

void kernel_cam(fp timeinst,
                global fp* d_initvalu,
                global fp* d_finavalu,
                int valu_offset,
                global fp* d_params,
                int params_offset,
                global fp* d_com,
                int com_offset,
                fp Ca){

    fp Btot;
    fp CaMKIItot;
    fp CaNtot;
    fp PP1tot;
    fp K;
    fp Mg;

    int offset_1;
    int offset_2;
    int offset_3;
    int offset_4;
    int offset_5;
    int offset_6;
    int offset_7;
    int offset_8;
    int offset_9;
    int offset_10;
    int offset_11;
    int offset_12;
    int offset_13;
    int offset_14;
    int offset_15;

    fp CaM;
    fp Ca2CaM;
    fp Ca4CaM;
    fp CaMB;
    fp Ca2CaMB;
    fp Ca4CaMB;
    fp Pb2;
    fp Pb;
    fp Pt;
    fp Pt2;
    fp Pa;
    fp Ca4CaN;
    fp CaMCa4CaN;
    fp Ca2CaMCa4CaN;
    fp Ca4CaMCa4CaN;

    fp Kd02;
    fp Kd24;
    fp k20;
    fp k02;
    fp k42;
    fp k24;

    fp k0Boff;
    fp k0Bon;
    fp k2Boff;
    fp k2Bon;
    fp k4Boff;
    fp k4Bon;

    fp k20B;
    fp k02B;
    fp k42B;
    fp k24B;

    fp kbi;
    fp kib;
    fp kpp1;
    fp Kmpp1;
    fp kib2;
    fp kb2i;
    fp kb24;
    fp kb42;
    fp kta;
    fp kat;
    fp kt42;
    fp kt24;
    fp kat2;
    fp kt2a;

    fp kcanCaoff;
    fp kcanCaon;
    fp kcanCaM4on;
    fp kcanCaM4off;
    fp kcanCaM2on;
    fp kcanCaM2off;
    fp kcanCaM0on;
    fp kcanCaM0off;
    fp k02can;
    fp k20can;
    fp k24can;
    fp k42can;

    fp rcn02;
    fp rcn24;

    fp B;
    fp rcn02B;
    fp rcn24B;
    fp rcn0B;
    fp rcn2B;
    fp rcn4B;

    fp Ca2CaN;
    fp rcnCa4CaN;
    fp rcn02CaN;
    fp rcn24CaN;
    fp rcn0CaN;
    fp rcn2CaN;
    fp rcn4CaN;

    fp Pix;
    fp rcnCKib2;
    fp rcnCKb2b;
    fp rcnCKib;
    fp T;
    fp kbt;
    fp rcnCKbt;
    fp rcnCKtt2;
    fp rcnCKta;
    fp rcnCKt2a;
    fp rcnCKt2b2;
    fp rcnCKai;

    fp dCaM;
    fp dCa2CaM;
    fp dCa4CaM;
    fp dCaMB;
    fp dCa2CaMB;
    fp dCa4CaMB;

    fp dPb2;
    fp dPb;
    fp dPt;
    fp dPt2;
    fp dPa;

    fp dCa4CaN;
    fp dCaMCa4CaN;
    fp dCa2CaMCa4CaN;
    fp dCa4CaMCa4CaN;

    Btot = d_params[params_offset+1];
    CaMKIItot = d_params[params_offset+2];
    CaNtot = d_params[params_offset+3];
    PP1tot = d_params[params_offset+4];
    K = d_params[16];
    Mg = d_params[17];

    offset_1 = valu_offset;
    offset_2 = valu_offset+1;
    offset_3 = valu_offset+2;
    offset_4 = valu_offset+3;
    offset_5 = valu_offset+4;
    offset_6 = valu_offset+5;
    offset_7 = valu_offset+6;
    offset_8 = valu_offset+7;
    offset_9 = valu_offset+8;
    offset_10 = valu_offset+9;
    offset_11 = valu_offset+10;
    offset_12 = valu_offset+11;
    offset_13 = valu_offset+12;
    offset_14 = valu_offset+13;
    offset_15 = valu_offset+14;

    CaM = d_initvalu[offset_1];
    Ca2CaM = d_initvalu[offset_2];
    Ca4CaM = d_initvalu[offset_3];
    CaMB = d_initvalu[offset_4];
    Ca2CaMB = d_initvalu[offset_5];
    Ca4CaMB = d_initvalu[offset_6];
    Pb2 = d_initvalu[offset_7];
    Pb = d_initvalu[offset_8];
    Pt = d_initvalu[offset_9];
    Pt2 = d_initvalu[offset_10];
    Pa = d_initvalu[offset_11];
    Ca4CaN = d_initvalu[offset_12];
    CaMCa4CaN = d_initvalu[offset_13];
    Ca2CaMCa4CaN = d_initvalu[offset_14];
    Ca4CaMCa4CaN = d_initvalu[offset_15];

    if (Mg <= 1){
        Kd02 = 0.0025*(1+K/0.94-Mg/0.012)*(1+K/8.1+Mg/0.022);
        Kd24 = 0.128*(1+K/0.64+Mg/0.0014)*(1+K/13.0-Mg/0.153);
    }
    else{
        Kd02 = 0.0025*(1+K/0.94-1/0.012+(Mg-1)/0.060)*(1+K/8.1+1/0.022+(Mg-1)/0.068);
        Kd24 = 0.128*(1+K/0.64+1/0.0014+(Mg-1)/0.005)*(1+K/13.0-1/0.153+(Mg-1)/0.150);
    }
    k20 = 10;
    k02 = k20/Kd02;
    k42 = 500;
    k24 = k42/Kd24;

    k0Boff = 0.0014;
    k0Bon = k0Boff/0.2;
    k2Boff = k0Boff/100;
    k2Bon = k0Bon;
    k4Boff = k2Boff;
    k4Bon = k0Bon;

    k20B = k20/100;
    k02B = k02;
    k42B = k42;
    k24B = k24;

    kbi = 2.2;
    kib = kbi/33.5e-3;
    kpp1 = 1.72;
    Kmpp1 = 11.5;
    kib2 = kib;
    kb2i = kib2*5;
    kb24 = k24;
    kb42 = k42*33.5e-3/5;
    kta = kbi/1000;
    kat = kib;
    kt42 = k42*33.5e-6/5;
    kt24 = k24;
    kat2 = kib;
    kt2a = kib*5;

    kcanCaoff = 1;
    kcanCaon = kcanCaoff/0.5;
    kcanCaM4on = 46;
    kcanCaM4off = 0.0013;
    kcanCaM2on = kcanCaM4on;
    kcanCaM2off = 2508*kcanCaM4off;
    kcanCaM0on = kcanCaM4on;
    kcanCaM0off = 165*kcanCaM2off;
    k02can = k02;
    k20can = k20/165;
    k24can = k24;
    k42can = k20/2508;

    rcn02 = k02*pow(Ca,2)*CaM - k20*Ca2CaM;
    rcn24 = k24*pow(Ca,2)*Ca2CaM - k42*Ca4CaM;

    B = Btot - CaMB - Ca2CaMB - Ca4CaMB;
    rcn02B = k02B*pow(Ca,2)*CaMB - k20B*Ca2CaMB;
    rcn24B = k24B*pow(Ca,2)*Ca2CaMB - k42B*Ca4CaMB;
    rcn0B = k0Bon*CaM*B - k0Boff*CaMB;
    rcn2B = k2Bon*Ca2CaM*B - k2Boff*Ca2CaMB;
    rcn4B = k4Bon*Ca4CaM*B - k4Boff*Ca4CaMB;

    Ca2CaN = CaNtot - Ca4CaN - CaMCa4CaN - Ca2CaMCa4CaN - Ca4CaMCa4CaN;
    rcnCa4CaN = kcanCaon*pow(Ca,2)*Ca2CaN - kcanCaoff*Ca4CaN;
    rcn02CaN = k02can*pow(Ca,2)*CaMCa4CaN - k20can*Ca2CaMCa4CaN;
    rcn24CaN = k24can*pow(Ca,2)*Ca2CaMCa4CaN - k42can*Ca4CaMCa4CaN;
    rcn0CaN = kcanCaM0on*CaM*Ca4CaN - kcanCaM0off*CaMCa4CaN;
    rcn2CaN = kcanCaM2on*Ca2CaM*Ca4CaN - kcanCaM2off*Ca2CaMCa4CaN;
    rcn4CaN = kcanCaM4on*Ca4CaM*Ca4CaN - kcanCaM4off*Ca4CaMCa4CaN;

    Pix = 1 - Pb2 - Pb - Pt - Pt2 - Pa;
    rcnCKib2 = kib2*Ca2CaM*Pix - kb2i*Pb2;
    rcnCKb2b = kb24*pow(Ca,2)*Pb2 - kb42*Pb;
    rcnCKib = kib*Ca4CaM*Pix - kbi*Pb;
    T = Pb + Pt + Pt2 + Pa;
    kbt = 0.055*T + 0.0074*pow(T,2) + 0.015*pow(T,3);
    rcnCKbt = kbt*Pb - kpp1*PP1tot*Pt/(Kmpp1+CaMKIItot*Pt);
    rcnCKtt2 = kt42*Pt - kt24*pow(Ca,2)*Pt2;
    rcnCKta = kta*Pt - kat*Ca4CaM*Pa;
    rcnCKt2a = kt2a*Pt2 - kat2*Ca2CaM*Pa;
    rcnCKt2b2 = kpp1*PP1tot*Pt2/(Kmpp1+CaMKIItot*Pt2);
    rcnCKai = kpp1*PP1tot*Pa/(Kmpp1+CaMKIItot*Pa);

    dCaM = 1e-3*(-rcn02 - rcn0B - rcn0CaN);
    dCa2CaM = 1e-3*(rcn02 - rcn24 - rcn2B - rcn2CaN + CaMKIItot*(-rcnCKib2 + rcnCKt2a));
    dCa4CaM = 1e-3*(rcn24 - rcn4B - rcn4CaN + CaMKIItot*(-rcnCKib+rcnCKta));
    dCaMB = 1e-3*(rcn0B-rcn02B);
    dCa2CaMB = 1e-3*(rcn02B + rcn2B - rcn24B);
    dCa4CaMB = 1e-3*(rcn24B + rcn4B);

    dPb2 = 1e-3*(rcnCKib2 - rcnCKb2b + rcnCKt2b2);
    dPb = 1e-3*(rcnCKib + rcnCKb2b - rcnCKbt);
    dPt = 1e-3*(rcnCKbt-rcnCKta-rcnCKtt2);
    dPt2 = 1e-3*(rcnCKtt2-rcnCKt2a-rcnCKt2b2);
    dPa = 1e-3*(rcnCKta+rcnCKt2a-rcnCKai);

    dCa4CaN = 1e-3*(rcnCa4CaN - rcn0CaN - rcn2CaN - rcn4CaN);
    dCaMCa4CaN = 1e-3*(rcn0CaN - rcn02CaN);
    dCa2CaMCa4CaN = 1e-3*(rcn2CaN+rcn02CaN-rcn24CaN);
    dCa4CaMCa4CaN = 1e-3*(rcn4CaN+rcn24CaN);

    d_finavalu[offset_1] = dCaM;
    d_finavalu[offset_2] = dCa2CaM;
    d_finavalu[offset_3] = dCa4CaM;
    d_finavalu[offset_4] = dCaMB;
    d_finavalu[offset_5] = dCa2CaMB;
    d_finavalu[offset_6] = dCa4CaMB;
    d_finavalu[offset_7] = dPb2;
    d_finavalu[offset_8] = dPb;
    d_finavalu[offset_9] = dPt;
    d_finavalu[offset_10] = dPt2;
    d_finavalu[offset_11] = dPa;
    d_finavalu[offset_12] = dCa4CaN;
    d_finavalu[offset_13] = dCaMCa4CaN;
    d_finavalu[offset_14] = dCa2CaMCa4CaN;
    d_finavalu[offset_15] = dCa4CaMCa4CaN;

    d_finavalu[com_offset] = 1e-3*(2*CaMKIItot*(rcnCKtt2-rcnCKb2b) - 2*(rcn02+rcn24+rcn02B+rcn24B+rcnCa4CaN+rcn02CaN+rcn24CaN));

}

translated_files.nearestNeighbor_kernel.cl:
kernel void euclid(
    const global LatLong* d_locations,
    global float* d_distances,
    int numRecords,
    float lat,
    float lng)
{
    int globalId = get_global_id(0);

    if (globalId < numRecords) {
        LatLong latLong = d_locations[globalId];
        d_distances[globalId] = sqrt((lat - latLong.lat) * (lat - latLong.lat) + 
                                     (lng - latLong.lng) * (lng - latLong.lng));
    }
}

typedef struct {
    float lat;
    float lng;
} LatLong;

kernel void euclid(LatLong *d_locations, float *d_distances, int numRecords, float lat, float lng) {
    int globalId = get_global_id(0);
    if (globalId < numRecords) {
        LatLong loc = d_locations[globalId];
